$ErrorActionPreference = "Stop"

$ProjectRoot = "C:\iau-deeds-lands-platform"
$FilePath = Join-Path $ProjectRoot "src\app\components\ThemeInitializer.tsx"

if (-not (Test-Path -LiteralPath $FilePath)) {
    throw "ThemeInitializer.tsx was not found."
}

$Timestamp = Get-Date -Format "yyyyMMdd-HHmmss"
$BackupPath = "$FilePath.backup-$Timestamp"
Copy-Item -LiteralPath $FilePath -Destination $BackupPath -Force

$Utf8NoBom = New-Object System.Text.UTF8Encoding($false)
$Content = [System.IO.File]::ReadAllText($FilePath, [System.Text.Encoding]::UTF8)

$ReplacementFunction = [System.Text.Encoding]::UTF8.GetString(
    [System.Convert]::FromBase64String("")
)

$FunctionPattern = 'const applyFontControls = \(settings: FontControlSettings\) => \{.*?\r?\n\};\r?\n\r?\nconst injectAppearanceStyles'

if ($Content -match 'allowColorOverrides = true') {
    Write-Host "Font override guard already exists."
} else {
    $FunctionReplacement = $ReplacementFunction + [Environment]::NewLine + [Environment]::NewLine + 'const injectAppearanceStyles'
    $Updated = [System.Text.RegularExpressions.Regex]::Replace(
        $Content,
        $FunctionPattern,
        $FunctionReplacement,
        [System.Text.RegularExpressions.RegexOptions]::Singleline
    )

    if ($Updated -eq $Content) {
        throw "Could not patch applyFontControls."
    }

    $Content = $Updated
    Write-Host "Patched applyFontControls."
}

$OldCall = 'applyFontControls(JSON.parse(storedFont));'
$NewCall = @'
applyFontControls(
          JSON.parse(storedFont),
          normalizedTheme.mode !== 'dark'
        );
'@

if ($Content.Contains($OldCall)) {
    $Content = $Content.Replace($OldCall, $NewCall.TrimEnd())
    Write-Host "Patched stored font settings."
} elseif ($Content -match "normalizedTheme\.mode !== 'dark'") {
    Write-Host "Stored font settings are already patched."
} else {
    throw "Could not patch the stored font call."
}

$CssBlock = [System.Text.Encoding]::UTF8.GetString(
    [System.Convert]::FromBase64String("")
)

if ($Content.Contains("FINAL_DARK_READABILITY_FIX")) {
    Write-Host "Final CSS layer already exists."
} else {
    $Marker = "    @media (max-width: 1279px) {"

    if (-not $Content.Contains($Marker)) {
        throw "Could not find the CSS insertion marker."
    }

    $Content = $Content.Replace(
        $Marker,
        $CssBlock + [Environment]::NewLine + [Environment]::NewLine + $Marker
    )

    Write-Host "Added final dark readability CSS."
}

[System.IO.File]::WriteAllText($FilePath, $Content, $Utf8NoBom)

Write-Host ""
Write-Host "DONE: dark theme readability fix applied."
Write-Host "Backup: $BackupPath"
Write-Host "Next: npm.cmd run build"
